export const articleContent: Record<string, ContentBlock[]> = {
  "18-maneder-etter-hofteoperasjon-hos-cmedical": [
    { type: "bold-intro", text: "Pasienthistorie:" },
    { type: "bold-intro", text: "«Mini og Muttern» er verdens første mor-datter-duo på Sydpolen. Etter 55 dager på ekspedisjon sto Emma «Mini» Gyllenhammar og moren Kathinka «Muttern» på verdens sørligste punkt." },
    { type: "quote", text: "– Det var enda mer spektakulært enn jeg hadde sett for meg, sier Emma." },
    { type: "paragraph", text: "For to år siden kunne hun knapt gå. Nå har hun gått 8-12 timer hver dag i over to måneder, med en pulk på over 100 kilo bak seg." },
    { type: "quote", text: "– Hvordan det gikk med hofta? Veldig bra, jeg hadde ikke vondt én eneste gang." },
    { type: "heading", text: "En mental utfordring" },
    { type: "paragraph", text: "Emma trodde det tøffeste skulle bli å nå frem til selve Sydpolen." },
    { type: "quote", text: "– Jeg var sikker på at jeg kom til å være utslitt og lei. Men da vi kom frem, følte jeg meg faktisk veldig bra. Vi var i en god flyt." },
    { type: "paragraph", text: "Den mentale kneiken kom tidligere, rundt dag 29, forteller hun." },
    { type: "quote", text: "– Vi hadde gått i en måned. Så slo det meg: Det er 45 dager igjen. Det var tungt. Du teller hele tiden – uker, timer og runde tall. Heldigvis er det konstante milepæler, og det var utrolig deilig å nyte en tid uten hverdagsstress og ting som venter på deg. Vi hadde ett mål, og det var å komme oss til Sydpolen sammen, og ikke minst ha det gøy på veien. Og det hadde vi." },
    { type: "quote", text: "– Ingenting overrasket oss. Vi hadde nok mat, sov godt og hadde varme nok klær. Mamma er ekstremt erfaren og nøye, og det har gjort meg nøye også." },
    { type: "heading", text: "55 dager. Ingen smerter." },
    { type: "paragraph", text: "For bare 18 måneder siden lå Emma på operasjonsbordet hos CMedical etter flere år med intense smerter. På en slik ekspedisjon er hoften spesielt utsatt når man trekker tung pulk dag etter dag." },
    { type: "quote", text: "– Det er egentlig helt utrolig at jeg i løpet av 55 dager ikke hadde vondt i hofta én eneste gang. Jeg var forberedt på at det kom til å gjøre vondt, og at jeg måtte gjøre øvelser underveis." },
    { type: "quote", text: "– Det vitner om en ekstremt vellykket operasjon. Det var første gang på mange år at jeg kunne gjøre det jeg hadde lyst til, uten at det gjorde vondt. Det var helt magisk. Jeg er så takknemlig for at jeg møtte Kristian M. Warholm og det dedikerte teamet ved CMedical – de så meg, tok meg på alvor og bidro til en behandling som har forandret livet mitt." },
    { type: "paragraph", text: "Antarktis er nesten helt stille, og turen besto av både vind, whiteout og snøfall, men også sol." },
    { type: "quote", text: "– Det var ingen forstyrrelser. Bare oss to. Det er jo mange som ønsker å dra på ekspedisjon alene, men for meg var den største verdien å dele opplevelsen med mamma. Vi var så fokuserte på arbeidsoppgavene at været nesten ikke spilte noen rolle. Jeg var bare utrolig takknemlig for å være der. Jeg har brukt så mange år – og hofteoperasjoner – på å komme dit. Også er det jo ingenting som er varmere enn en mors trygghet." },
    { type: "paragraph", text: "På spørsmål om et av de sterkeste minnene, trekker hun frem en helt «vanlig» dag." },
    { type: "quote", text: "– Vi lå i teltet og drakk kakao etter dagens økt. Jeg tenkte bare på hvor heldig jeg var som fikk være der. Med mamma." },
    { type: "paragraph", text: "Kontrasten er stor. Fra å knapt kunne gå, til å gå 25 kilometer på ski hver dag i 55 dager." },
    { type: "quote", text: "– Jeg så hvor fort livet kan snu. Det gjør at jeg setter enda mer pris på det. For to år siden var det ingen garanti for at jeg skulle stå der." },
    { type: "quote", text: "– Nå vet jeg at det er mulig å komme tilbake." },
  ],

  "overgangsalderen-er-en-ny-fase-ikke-slutten-pa-noe": [
    { type: "author", text: "Av Unni-Lovise Godager Berge, CMedical" },
    { type: "paragraph", text: "Symptomene på overgangsalderen starter ofte tidligere enn mange tror, som regel i første halvdel av 40-årene og opp til 10 år før menstruasjonen uteblir. For noen kvinner er overgangen knapt merkbar, mens andre opplever så store utfordringer at det påvirker både hverdagen og livskvaliteten." },
    { type: "quote", text: "– «Overgangsalderen er en naturlig del av livet, men for mange kan symptomene være både overveldende og forvirrende. Jeg møter mange kvinner som ikke helt forstår hva som skjer med kroppen deres, og som kanskje heller ikke blir tatt på alvor,» sier Birgitte Mitlid-Mork, gynekolog og spesialist i overgangsalder ved CMedical." },
    { type: "heading", text: "Store individuelle forskjeller" },
    { type: "paragraph", text: "De første tegnene kan ofte merkes gjennom uregelmessige menstruasjoner og hetetokter. Mange opplever også endringer i humør, søvnvansker og redusert energi." },
    { type: "quote", text: "– «Noen merker knapt at de går gjennom en hormonell endring, mens andre får symptomer som påvirker både jobb, familieliv og selvfølelse. Det er store individuelle forskjeller, og derfor finnes det heller ingen 'one size fits all'-løsning,» forklarer Birgitte." },
    { type: "subheading", text: "Vanlige symptomer inkluderer blant annet:" },
    { type: "list", items: ["Blødningsforstyrrelser", "Hetetokter og nattesvette", "Hjernetåke og konsentrasjonsvansker", "Søvnproblemer", "Emosjonell ustabilitet", "Smerter i muskler og ledd", "Endringer i hud og hår", "Redusert sexlyst og tørrhet i skjeden"] },
    { type: "paragraph", text: "Selve menopausen defineres som tidspunktet der menstruasjonen har uteblitt i 12 måneder. Men perioden før, den såkalte perimenopausen, kan vare i flere år." },
    { type: "quote", text: "– «Dette er en tid hvor hormonnivåene svinger, og det påvirker hele kroppen. Mange får symptomer som de ikke forbinder med overgangsalder, som angst, lavt energinivå eller smerter i kroppen,» sier Birgitte." },
    { type: "paragraph", text: "Hun understreker at nedgangen i østrogen, progesteron og testosteron ikke bare gir plager her og nå, men også kan øke risikoen for beinskjørhet, hjerte- og karsykdommer og depresjon på sikt." },
    { type: "quote", text: "– «Derfor er det viktig å ta symptomer på alvor, ikke bare for å bedre livskvaliteten, men også for å forebygge fremtidige helseproblemer,» sier hun." },
    { type: "paragraph", text: "Mange blir feildiagnostisert, og sendt hjem med medisiner for angst og depresjon, men så viser det seg at det handler om overgangsalder, og symptomene må behandles på en helt annen måte." },
    { type: "heading", text: "Helhetlig behandling, skreddersydd for deg" },
    { type: "paragraph", text: "Hos CMedical tilbys en grundig kartleggingssamtale der kvinnens livssituasjon og helse gjennomgås i detalj. Samtalen varer i omtrent 45 minutter og inkluderer medisinsk vurdering, blodprøver ved behov og utarbeidelse av en personlig behandlingsplan." },
    { type: "quote", text: "– «Vårt mål er at hver pasient skal føle seg både sett og hørt, uansett hvilken fase i livet hun er i. Det finnes gode og trygge behandlingsalternativer som kan gi bedre livskvalitet og gjøre denne fasen lettere å håndtere,» forteller Birgitte." },
    { type: "paragraph", text: "Behandlingen kan også inkludere tverrfaglig samarbeid med andre fagpersoner hos CMedical, som ernæringsfysiolog, osteopat, psykolog eller sexolog, alt basert på den enkeltes behov." },
    { type: "heading", text: "Et tverrfaglig ekspertteam" },
    { type: "paragraph", text: "Ved CMedical møter pasientene et dedikert team av spesialister på overgangsalder: Ida Bjørntvedt, Birgitte Aspenes, Birgitte Mitlid-Mork og Madeleine Engen. Alle er medlemmer av British Menopause Society, og klinikken samarbeider med Newson Health i Storbritannia som er verdens ledende klinikk innen overgangsalder." },
    { type: "quote", text: "– «Vi jobber etter prinsippet om de fire søylene; hormoner, relasjoner, ernæring og fysisk form. Når disse delene balanseres, oppnår vi den beste helheten for pasientene våre,» forklarer Birgitte." },
    { type: "heading", text: "Et viktig budskap til alle kvinner" },
    { type: "quote", text: "– «Overgangsalderen handler ikke om å miste noe, men om å gå inn i en ny fase av livet. Med riktig kunnskap og behandling kan kvinner oppleve mer energi, bedre søvn, bedre humør, og større trygghet i egen kropp,» sier Birgitte Mitlid-Mork." },
  ],

  "nar-kroppen-ikke-fungerer-etter-fodsel-og-ingen-lytter": [
    { type: "author", text: "Av Madeleine Engen, gynekolog og gründer av CMedical kvinnehelse" },
    { type: "paragraph", text: "Jeg spesialiserte meg innen gynekologi med spesiell interesse og ekspertise innen vaginalt fremfall, fordi jeg var sjokkert over hvor mange kvinner som rammes og lider i stillhet. I hverdagen møter jeg kvinner helt ned i 20-årene som lever med nedpress, vanskeligheter med å gå på do eller vannlatingstrang, en kropp som ikke lenger fungerer etter fødsel. De får ikke hjelp. Mange går i årevis uten å få diagnose, veiledning eller hjelp." },
    { type: "quote", text: "«Du må bare gjøre noen knipeøvelser», «Her er alt normalt, du har jo født, det er sånn det ser ut etter fødsel»" },
    { type: "paragraph", text: "Dette er ord mine pasienter har fått høre når de har bedt om hjelp, både fra offentlige og private helsetjenester. Holdninger som avslører et alvorlig kunnskapsgap i helsevesenet." },
    { type: "heading", text: "Vaginalt fremfall er en av de vanligste og mest oversette fødselsskadene." },
    { type: "paragraph", text: "Ifølge WHO får 36 prosent av kvinner som føder vaginalt permanente sekveler. Likevel er det mange som ikke blir tatt på alvor." },
    { type: "paragraph", text: "Vaginalt fremfall, også kalt underlivsprolaps, oppstår når skjedevegger, livmorhals eller livmor synker og buler inn eller ut av skjedeåpningen. Symptomene kan variere avhengig av skaden, fra nedpress, bulkfølelse, hyppig vannlating, vansker med å late vannet eller ved avføring, pinlige lyder fra skjeden eller redusert følelse under samleie. Bekkenbunnstrening under kyndig veiledning burde være et minimumstilbud. Men i mange tilfeller er kirurgi eneste vei til bedring." },
    { type: "heading", text: "Varsko om fallende fødselstall" },
    { type: "paragraph", text: "I media og fra politikere ropes det varsko om fallende fødselstall. Norge har i dag et av de laveste fruktbarhetstallene i Europa, og politikere slår alarm om at vi får altfor få barn til å opprettholde velferdssamfunnet." },
    { type: "paragraph", text: "Årsaken til denne nedgangen er sammensatt, men vi kan ikke snakke om fødselstall uten å snakke om kvinnehelse. Vil en kvinne som fortsatt går rundt med ubehandlede fødselsskader etter første fødsel i det hele tatt vurdere å få sitt andre eller tredje barn?" },
    { type: "paragraph", text: "Vil vi øke fødselstallene, må vi ta kvinners helse før, og etter, fødsel på alvor. Det innebærer å ruste opp barsels- og etterfødselsomsorgen, sikre tidlig diagnostisering og behandling av fødselsskader, og heve kompetansen på dette området i helsevesenet." },
    { type: "paragraph", text: "I en årrekke var jeg selv plaget uten å få riktig hjelp ved en kvinnelidelse. Jeg vet hvordan det er å få feile diagnoser og behandlinger som gjør ting verre, hvordan tilliten svikter og mye kjennes håpløst. Først etter åtte år møtte jeg helsepersonell med riktig kompetanse på det som feilte meg, og da ble jeg frisk. Jeg er ikke alene om denne erfaringen. Det er rett og slett ikke godt nok." },
    { type: "bold-intro", text: "Hvis vi virkelig vil ha flere barn i dette landet, burde vi ikke begynne med å ta vare på dem som faktisk føder barna? Før, under og etter." },
  ],

  "minis-historie-gjennom-mutterns-oyne": [
    { type: "paragraph", text: "For Kathinka «Muttern» Gyllenhammar er det å lede mennesker gjennom polare områder en del av jobben. Men ingenting kunne forberede henne på den reisen datteren Emma «Mini» skulle gjennom; fra hofteskade og operasjon, til rehabilitering og forberedelser til en av verdens tøffeste ekspedisjoner." },
    { type: "paragraph", text: "Emma var 17 år, aktiv fotballspiller og turjente med drømmer om å følge morens skispor mot Sydpolen. Men skaden i hoften satte alt på vent." },
    { type: "link", text: "Les Emmas historie her: Fra operasjonsbordet til Sydpolen på 14 måneder", url: "/aktuelt/fra-operasjonsbordet-til-sydpolen-pa-14-maneder" },
    { type: "quote", text: "– Det var forferdelig å se henne slik. Det er tungt å se en så aktiv unge få begrensninger. Vi prøvde alt, men da hun kom hjem fra USA, var hun ganske ødelagt. Det var første gang vi skjønte hvor alvorlig det var, forteller Kathinka." },
    { type: "paragraph", text: "Tidligere hadde Emma blitt operert uten at det ga ønsket resultat, snarere tvert imot. Smertene ble verre, og hverdagen stadig mer begrenset." },
    { type: "paragraph", text: "Da idrettskarrieren sto i ruiner fikk Emma rådet om å oppsøke ortopedkirurg Kristian Warholm ved CMedical, en erfaren spesialist innen hofteoperasjoner, også for idrettsutøvere. Det ble besluttet at Emma måtte opereres på nytt, og Kathinka kjente både frykt og lettelse." },
    { type: "quote", text: "– Jeg ble redd for at hun igjen skulle få falske forhåpninger, at det ikke skulle gå bra. Samtidig var jeg lettet over at noen faktisk så henne, og trodde hun kunne bli bedre. Det betydde alt, forteller hun." },
    { type: "paragraph", text: "Hun var selv på ekspedisjon på Grønland da Emma ble operert, og fulgte prosessen tett på avstand." },
    { type: "quote", text: "– Da jeg kom hjem, var både Emma og faren hennes utrolig fornøyde. De følte seg trygge og godt ivaretatt. Oppfølgingen fra både Kristian og CMedical har vært fantastisk i ettertid, sier hun." },
    { type: "paragraph", text: "Etter operasjonen gikk det fort. Bare måneder senere var Emma tilbake i full trening, og våren etter krysset hun Nordvestpassasjen sammen med moren, hele 400 kilometer over is og snø." },
    { type: "quote", text: "– Det betyr alt å se henne få livet tilbake. Hun har alltid vært en aktiv jente, og nå er hun tilbake der hun trives, med kroppen som fungerer. Det er helt fantastisk, sier Kathinka." },
    { type: "heading", text: "Mor og ekspedisjonsleder" },
    { type: "paragraph", text: "Mini og Muttern reiste i november 2025 og vil bli verdens første mor-datter-duo som når Sydpolen. For Kathinka betyr det en dobbel rolle, både som mor og ekspedisjonspartner." },
    { type: "quote", text: "– Det er stor forskjell på de rollene, men kanskje ikke så stor likevel. Jeg vil være den med mest erfaring der ute, men Emma har mye kunnskap hun også. Jeg vet hva hun kan, og hva jeg kan forvente. Den største forskjellen er kanskje at vi som familie vet hvilke knapper vi kan trykke på, sier hun med et smil og avslutter:" },
    { type: "quote", text: "– 75 dager i et lite telt blir både utfordrende og fantastisk. Vi har bare hverandre der ute og må ta vare på hverandre. Takk til CMedical for denne muligheten. Jeg gleder meg enormt, sier hun." },
    { type: "link", text: "Les mer om hvordan de har forberedt seg her: Slik forbereder hun seg til Sydpolen", url: "/aktuelt/slik-forbereder-hun-seg-til-sydpolen" },
  ],

  "slik-forbereder-hun-seg-til-sydpolen": [
    { type: "paragraph", text: "Etter to år med intense smerter tross tidligere kirurgi måtte Emma «Mini» Gyllenhammar starte helt på nytt. Nå, etter en vellykket hofteoperasjon hos CMedical, trener hun systematisk mot et av verdens mest ekstreme mål: en polarekspedisjon til Sydpolen." },
    { type: "quote", text: "– Jeg tror fortsatt ikke helt at det skjer. Noe i meg tør ikke tro på det før jeg faktisk står der, sier hun." },
    { type: "paragraph", text: "Emma beskriver treningen som en reise i seg selv – en hun aldri ville vært i stand til å gjennomføre uten ny operasjon hos CMedical. Treningen består i stor grad av å trekke bildekk, både på asfalt og grus, for å simulere vekten av pulken hun skal dra etter seg gjennom snø og is." },
    { type: "quote", text: "– Først starter man med ett bildekk, så øker man til to, tre. Det er stor forskjell på underlaget, for eksempel er asfalt mye tyngre enn på grus. Siden jeg bor i byen, trener jeg mest på asfalt. I tillegg har jeg et litt annet utgangspunkt med hoften min som er operert, forteller hun." },
    { type: "paragraph", text: "Ifølge Emma står også yogaøvelser og badstue høyt på prioriteringslisten for å sikre god bevegelighet." },
    { type: "quote", text: "– Man må kunne sitte bøyd i telt i 70 dager. Jeg har fortsatt noen svakheter i hoften, men det er ikke nærheten så ille som det var. Da hjelper det veldig med varmebehandling og gode yogaøvelser for hoften, forteller hun." },
    { type: "paragraph", text: "Kristian Marstrand Warholm er ortopeden bak den vellykkede operasjonen som ga hoftekulen bedre plass og bevegelighet. Han er både rørt og imponert over innsatsen Emma har lagt i rehabiliteringen." },
    { type: "quote", text: "– Historien til Emma viser hva moderne ortopedi kan utrette når kirurgi, riktig oppfølging og pasientens egen innsats spiller sammen. For oss på CMedical er det sterkt å se en pasient gå fra å knapt kunne gå, til å trene til Sydpolen på bare litt over et år, sier Warholm." },
    { type: "heading", text: "«Hvis du ikke er litt redd, har du gjort noe feil»" },
    { type: "paragraph", text: "Det er mye man må tenke på når man skal begi seg ut på en ekspedisjon til Sydpolen. Selv om Kathinka «Muttern» er en erfaren polfarer, er det visse bekymringer som ligger til grunn." },
    { type: "quote", text: "– Mamma sier alltid at hvis du ikke er litt redd, så har du gjort noe feil. Jeg er mest nervøs for hvordan kroppen takler det etter 30, 40, 50 dager, sier Emma." },
    { type: "paragraph", text: "Hun har gått lange ekspedisjoner før, blant annet gjennom Nordvestpassasjen, men aldri i 70 dager sammenhengende. Muttern er Norges første kvinnelige internasjonalt godkjente polarguide (IPGA), og har Grønland, Antarktis og Nordvestpassasjen som sine arbeidssteder." },
    { type: "quote", text: "– Det er ikke egentlig distansen eller kulden jeg er redd for. Det er usikkerheten i det langvarige. Hva skjer når man har gått på ski hver eneste dag i to måneder? Hva gjør det med kroppen? Hva gjør det med hodet?" },
    { type: "quote", text: "– At teltet brenner. Dersom man søler bensin og det tar fyr, er det lite som kan redde deg på Sydpolen. Teltet er livsnerven. Mister du det, er det over." },
    { type: "heading", text: "Kvinnehelse på tur" },
    { type: "paragraph", text: "I tillegg til ekstrem kulde og fysisk belastning, må kvinnelige polfarere ta høyde for utfordringer som sjelden snakkes om." },
    { type: "quote", text: "– Kvinner er mer utsatt for det som kalles polar thighs. Det begynner som små myggstikk på lår og rumpe, og kan utvikle seg til betente sår som må evakueres for. Det er derfor jeg går med dunshorts og dunskjørt hele tiden. Jeg skal ikke bli kald der, forteller Emma." },
    { type: "paragraph", text: "Hun snakker også om menstruasjon, som er krevende i et miljø hvor man ikke får vasket hendene på mange døgn." },
    { type: "quote", text: "– Mens menn i stor grad våkner opp likt hver dag, går kvinner gjennom fire ulike hormonelle faser i løpet av en måned. Når vi er på tur i over to måneder, går vi gjennom hele den runden to ganger. Det påvirker energi, smerteopplevelse og følelser – alt. Men det er ikke noe man kan styre. Det er bare å jobbe med det, ikke mot det, sier Emma." },
    { type: "paragraph", text: "For Emma handler reisen ikke bare om å trene kroppen til en ekspedisjon i verdens tøffeste klima. Det handler også om å aldri gi opp når livet stanser opp." },
    { type: "quote", text: "– Aldri gi opp. Ikke ta et nei for et nei. Det finnes alltid en fagperson som kan hjelpe deg. For meg var det Kristian Warholm som virkelig så meg og trodde på at jeg kunne bli bedre. Det gjorde alt, sier Emma." },
  ],

  "robotassistert-overvektskirurgi-presisjon-trygghet-og-varige-resultater": [
    { type: "paragraph", text: "Som den eneste private aktøren i Norden tilbyr CMedical robotassistert overvektskirurgi med høyeste presisjon og skånsomhet. Med avansert 3D-visualisering og mikrobevegelser styrt av erfarne kirurger, får du en trygg behandling som kan gi mindre smerter og raskere restitusjon." },
    { type: "heading", text: "Hva er robotassistert sleeve gastrektomi (rSG)?" },
    { type: "paragraph", text: "Slankeoperasjon med Sleeve gastrektomi er en moderne metode der 60–80 % av magesekken fjernes. Den gjenværende delen formes til en bananformet «sleeve», som gjør at du får mindre sultfølelse, spiser mindre og oppnår varig vektreduksjon, uten å gå på kompromiss med kroppens evne til å ta opp næringsstoffer." },
    { type: "paragraph", text: "Robotassistert teknikk gjør prosedyren mer presis enn tradisjonell laparoskopi. Kirurgen styrer hele inngrepet fra en konsoll, og avansert teknologi oversetter hånd- og fingerbevegelser til mikrobevegelser i instrumentene." },
    { type: "quote", text: "– Det er viktig å understreke at det ikke er en robot som opererer deg. Hele prosedyren styres av en erfaren kirurg – teknologien gir oss bare enda større presisjon og kontroll, forklarer Dr. Jan Roland Lambrecht, fagansvarlig gastrokirurg hos CMedical." },
    { type: "heading", text: "Fordeler med robotassistert kirurgi" },
    { type: "list", items: ["Mindre smerter og kortere restitusjonstid", "Redusert blodtap og færre komplikasjoner", "Bedre kosmetisk resultat gjennom små snitt", "Raskere tilbake i hverdagen – mange reiser hjem dagen etter operasjonen", "Kortere sykemelding – ofte bare to uker"] },
    { type: "paragraph", text: "Etter ett år kan pasienter som gjennomgår sleeve gastrektomi forvente et vekttap på 20-25 % av total kroppsvekt samt varig forbedring av helserelatert livskvalitet." },
    { type: "quote", text: "– Mange pasienter opplever at dette blir starten på et nytt liv – med mer energi, bedre helse og en hverdag der vekten ikke lenger er en barriere, sier Dr. Andreas Edenberg, spesialist i gastroenterologisk kirurgi." },
    { type: "heading", text: "Trygg behandling hos erfarne spesialister" },
    { type: "paragraph", text: "CMedical har over 7 års erfaring med robotassisterte inngrep, og våre kirurger kombinerer høy faglig presisjon med tett oppfølging." },
    { type: "list", items: ["Dr. Jan Roland Lambrecht har over 25 års erfaring fra Norge og Danmark, og er en anerkjent ekspert innen overvektskirurgi, brokkirurgi og robotassistert kirurgi.", "Dr. Andreas Edenberg er spesialist i generell- og gastrokirurgi, med særlig kompetanse på fedmebehandling og avansert endoskopi."] },
    { type: "heading", text: "Forberedelser og oppfølging" },
    { type: "paragraph", text: "Godt forarbeid gir best resultat. Før operasjonen vil du møte vårt tverrfaglige team, inkludert ernæringsfysiolog, som veileder deg i kosthold og livsstilsendringer. Blant annet anbefales en lavkaloridiett i tre uker før inngrepet for å gjøre operasjonen enklere og tryggere." },
    { type: "quote", text: "– For oss handler det ikke bare om selve inngrepet, men om å gi pasientene de riktige verktøyene for å oppnå et stabilt og sunt vekttap. Trygghet, presisjon og oppfølging står i sentrum, understreker Jan Roland Lambrecht." },
    { type: "heading", text: "Ta det første steget" },
    { type: "paragraph", text: "Vil du vite mer om hvordan en sleeve gastrektomi kan hjelpe deg med vektreduksjon og økt livskvalitet? Hos CMedical får du en uforpliktende samtale med en av våre erfarne kirurger – der du får svar på spørsmål, realistiske forventninger og en plan som passer deg." },
  ],

  "fra-operasjonsbordet-til-sydpolen-pa-14-maneder": [
    { type: "paragraph", text: "Emma «Mini» Gyllenhammar var bare 17 år da alt raknet. En alvorlig hofteskade tok fra henne hverdagsglede og drømmen om å følge morens skispor til Sydpolen. Etter en mislykket operasjon levde hun i to år med konstante smerter, og et liv satt på vent. Men med hjelp fra CMedical fikk Emma livet tilbake. Nå forbereder seg til sitt livs største eventyr: å gå til Sydpolen med mamma «Muttern»." },
    { type: "paragraph", text: "Emma har alltid vært en eventyrer. Som tenåring deltok hun på ekspedisjoner sammen med moren Kathinka, Norges første kvinnelige internasjonalt godkjente polarguide (IPGA). Som 14-åring ble hun tidenes yngste til å fullføre det 100 km lange polare skiløpet Expedition Amundsen. Hun kombinerte en aktiv friluftsoppvekst med en lovende fotballkarriere, og som 17-åring tok hun laget sitt til seier i California State Championship-finalen." },
    { type: "paragraph", text: "Men bak suksessen lurte en skade. En hofteskade som brått satte en stopper for idrettsdrømmen." },
    { type: "quote", text: "– Jeg hadde alltid hatt smerter, men de ble holdt i sjakk med behandling. Til slutt fikk jeg beskjed om at det var nødvendig med en operasjon, og etter den første operasjonen i 2022 ble alt mye verre. Jeg klarte ikke å løpe, knapt å gå. Jeg følte kroppen min var ødelagt. Og drømmen om Sydpolen var plutselig knust, forteller Emma." },
    { type: "heading", text: "Vendepunktet hos CMedical" },
    { type: "paragraph", text: "Da idrettskarrieren sto i ruiner, fikk Emma rådet om å oppsøke kirurg Kristian Warholm ved CMedical. Han har lang erfaring med hofteoperasjoner, også på idrettsutøvere." },
    { type: "quote", text: "– Da jeg først møtte Emma, var hun på et dårlig sted. Hun var sterkt preget av smerter i hverdagen, og hadde mistet mye funksjon, forteller Warholm." },
    { type: "paragraph", text: "Under inngrepet fant han en tydelig årsak: hoftekulen passet ikke inn i hofteskålen." },
    { type: "quote", text: "– Dette er en type operasjon som krever spesialisert utstyr, riktig kompetanse og erfaring. Hofteleddet er et komplisert ledd, og når kulen ikke passer i skålen, blir hver bevegelse smertefull. Hos Emma var situasjonen ekstra utfordrende fordi hun hadde gått lenge med skaden. Vi visste vi måtte være svært presise for å gi henne funksjonen tilbake, sier han." },
    { type: "quote", text: "– Jeg var livredd. En tidligere mislykket hofteoperasjon hadde satt meg helt ut, og tanken på å gå gjennom det en gang til var nesten uutholdelig. Men etter gode og betryggende samtaler med Warholm våget jeg likevel. Inngrepet tok lenger tid enn planlagt fordi ingen visste helt hva som var galt, men jeg kjente med en gang etterpå at noe var annerledes. Smertene var borte, og det var som jeg hadde mer plass i hoften til bevegelse, sier hun." },
    { type: "paragraph", text: "Rehabiliteringen gikk raskt fremover. Allerede tre måneder etter operasjonen trente hun styrke, og innen jul var hun ute og dro dekk gatelangs. Våren etter gikk hun 400 km gjennom Nordvestpassasjen i Nord-Canada – over pakkis, skruis og temperaturer ned mot -40 grader – sammen med muttern." },
    { type: "quote", text: "– Å klare den turen, bare seks måneder etter operasjonen, ga meg en mestringsfølelse jeg aldri har kjent på før, sier Emma." },
    { type: "quote", text: "– Det aller viktigste har vært Emmas egen vilje og arbeid med opptreningen. Hun har vist en helt enorm innsats, og det er den kombinasjonen som gjør at hun står der hun gjør i dag, sier Warholm." },
    { type: "heading", text: "Mot Sydpolen" },
    { type: "paragraph", text: "I november 2025 reiser Emma og moren Kathinka ut på ekspedisjon. Sammen blir de verdens første mor-datter-duo til å gå til Sydpolen." },
    { type: "quote", text: "– Jeg trodde drømmen min var tapt. Men takket være CMedical og operasjonen fikk jeg en ny sjanse. Nå er jeg klar for mitt livs største eventyr." },
  ],

  "livio-oslo-blir-en-del-av-cmedical-og-tilbudet-til-pasientene-styrkes": [
    { type: "paragraph", text: "I 1986 åpnet den første private fertilitetsklinikken i Norge. Livio Oslo – den gang kjent som IVF-klinikken – har siden vært en pioner innen assistert befruktning. Gjennom snart 40 år har klinikken bidratt til at over 3500 barn har kommet til verden." },
    { type: "paragraph", text: "Nå har Livio Oslo blitt en del av CMedical, og pasientene får tilgang til en unik kombinasjon av moderne teknologi, kirurgisk kompetanse og lang erfaring innen fertilitetsbehandling." },
    { type: "quote", text: "«Fordelene med at vi nå slår oss sammen er at pasientene får tilgang til et bredere behandlingstilbud, flere spesialister på samme sted, samt god kompetanse og teknologi fra begge klinikker», sier Kjersti Brenden, gynekolog og fertilitetsspesialist fra Livio Oslo." },
    { type: "heading", text: "En unik kombinasjon" },
    { type: "paragraph", text: "CMedical er den første klinikken i Norden som samler fertilitetsbehandling og kirurgi under samme tak. Med toppmoderne utstyr, en høyteknologisk fertilitetslab og et bredt tverrfaglig team, blir behandlingen helhetlig og trygg – fra pubertet og graviditet til barseltid og tiden etter fødsel." },
    { type: "quote", text: "«Med topp moderne teknologi og fertilitetsbevarende robotkirurgi kan vi tilby en mer helhetlig omsorg og behandling av en utfordring som kan være kompleks. Dette gir trygghet underveis – noe som skiller oss ut i et felt hvor presisjon og samarbeid på tvers er avgjørende», sier Birgitte Mitlid-Mork, Gynekolog og fertilitetsspesialist fra CMedical." },
    { type: "heading", text: "Erfaring som bygger trygghet" },
    { type: "paragraph", text: "Livio Oslo har vært en viktig aktør i norsk fertilitetshistorie, og bringer med seg nesten fire tiår med erfaring." },
    { type: "quote", text: "«De viktigste erfaringene vi har gjort oss etter snart 40 år med fertilitetsbehandling er at utvikling over tid har gitt trygghet og erfaring. Vi har hele tiden hatt fokus på individualisert pasientoppfølging», forteller Kjersti." },
    { type: "heading", text: "Flere søker behandling i dag" },
    { type: "paragraph", text: "Ufrivillig barnløshet rammer mellom 8–12 % av par i Norge. Samtidig ser man at flere søker hjelp i dag enn tidligere – både på grunn av økt åpenhet og endringer i lovverket." },
    { type: "quote", text: "«Holdningene til assistert befruktning har blitt mye mindre tabubelagt enn før. Når man spør, kjenner nesten alle noen som har vært gjennom en behandling», sier Birgitte." },
    { type: "heading", text: "Et bredt tverrfaglig tilbud" },
    { type: "paragraph", text: "Et særpreg ved CMedical er bredden i tilbudet. Klinikken har spesialister på sykdommer som rammer mange infertile, som PCOS og endometriose, og et eget ekspertteam på avansert endometriosekirurgi." },
    { type: "quote", text: "«Vi følger pasienten tett før, under og etter fertilitetsprosessen. I tillegg til fertilitetsbehandlingen tilbyr vi oppfølging fra fostermedisinere, fødselsleger, bekkebunnsosteopater og gynekologer med kompetanse på fødselsskader. Vi har også et bredt tverrfaglig team bestående av fertilitetscoach, ernæringsfysiolog, sexolog og psykolog – alt under samme tak. Dette er helt unikt», understreker Birgitte." },
    { type: "heading", text: "Det beste fra to verdener" },
    { type: "paragraph", text: "Med Livio Oslo og CMedical sammen får pasientene en kombinasjon av erfaring, trygghet og moderne teknologi – alt samlet på ett sted. Dette gir pasientene et helhetlig og fremtidsrettet tilbud, der både kropp og sinn blir ivaretatt." },
  ],

  "historiene-ingen-snakker-om-etter-fodsel": [
    { type: "paragraph", text: "For mange kvinner er det krevende å snakke om plager etter fødsel. Skader kan være usynlige utad, men likevel sette dype spor både fysisk og psykisk." },
    { type: "paragraph", text: "«Astrid» (50) er en av mange som har opplevd dette, og som til slutt fant hjelpen hun trengte hos vår gynekolog, Madeleine Engen." },
    { type: "paragraph", text: "I en artikkel publisert i Nettavisen forteller «Astrid» om en lang reise fra fødselsskade til flere operasjoner, og hvordan møtet med Madeleine til slutt ble vendepunktet. «Astrid» ønsker å være anonym pga skammen hun opplever preger denne type helseproblematikk." },
    { type: "heading", text: "Mange år med smerter og usynlige skader" },
    { type: "paragraph", text: "Etter fødselen av sitt første barn i 2000 fikk hun beskjed om at smertene og plagene hun opplevde var «helt normale». Selv da muskulaturen innvendig var helt revnet, ble hun møtt med råd om knipeøvelser. Først etter en privat operasjon to år senere fikk hun livet tilbake – men anbefalingen var at hun måtte gjennomføre en ny operasjon senere i livet." },
    { type: "paragraph", text: "Da hun høsten 2024 fulgte dette rådet, ble resultatet det motsatte: Smertene ble verre enn noen gang, og hun endte opp på krykker. For «Astrid» ble dette starten på en tung periode der hverdagen føltes umulig å håndtere." },
    { type: "heading", text: "Fant hjelpen hos CMedical" },
    { type: "paragraph", text: "Vinteren 2025 kom hun til CMedical, og møtte Madeleine Engen – gynekolog med særlig kompetanse på fødselsskader. For første gang på mange år følte hun seg sett og forstått." },
    { type: "quote", text: "– Hun kom til oss som en svært traumatisert pasient. Skadene hennes var så omfattende at jeg først trodde hun aldri hadde vært operert, forteller Madeleine." },
    { type: "paragraph", text: "Engen rekonstruerte muskulaturen i mellomkjøttet, slik at bekkenbunnen igjen fikk støtte og hold. Allerede kort tid etter operasjonen kunne «Astrid» legge bort krykkene." },
    { type: "heading", text: "Behovet for et løft i kvinnehelse" },
    { type: "quote", text: "– Jeg ønsker å fortelle min historie fordi jeg vet det er mange flere der ute. Altfor mange kvinner lever med plager de ikke skulle hatt, sier hun til Nettavisen." },
    { type: "quote", text: "– Altfor mange kvinner blir bagatellisert eller feilbehandlet. Vi skylder kvinner mer enn dette. Kompetansen på kvinnehelse må styrkes, sier Madeleine Engen." },
    { type: "paragraph", text: "Hos CMedical møter vi daglig kvinner med alt fra fødselsskader til endometriose og overgangsplager. Vårt mål er å tilby høyeste faglige kompetanse og omsorg, slik at ingen skal stå alene med sine utfordringer." },
    { type: "source", text: "Kilde: Nettavisen, 2025 – «Privatklinikk ble siste utvei: – Reddet livet mitt»", url: "https://www.nettavisen.no/nyheter/gikk-privat-for-a-rette-opp-feil-reddet-livet-mitt/s/5-95-2602574" },
  ],

  "jeg-matte-grate-pa-telefonen-for-a-bli-tatt-pa-alvor": [
    { type: "bold-intro", text: "Da Kristine fikk sin første sønn, forventet hun en normal tilhelingsprosess. Men smertene var uutholdelige, til og med en enkel trilletur ble umulig. – Jeg visste at noe var galt, men ingen ville høre på meg. Jeg hørte gang på gang at dette var helt normalt, sier Kristine Flygind Bjerke." },
    { type: "paragraph", text: "Hun forteller videre at hun gjennom flere måneder oppsøkte både private og offentlige spesialister i håp om å få svar, men ingen fant noe galt." },
    { type: "quote", text: "– Det føltes som om underlivet mitt var på vei ut. En helt utrolig ubehagelig følelse som snudde livet mitt på hodet. Jeg klarte ikke å være den mammaen jeg ønsket å være, og jeg så mitt aktive liv forsvinne. «Er det virkelig sånn jeg skal leve?», husker jeg at jeg tenkte, forteller Bjerke." },
    { type: "heading", text: "– Følte meg som en kasteball" },
    { type: "paragraph", text: "De første to ukene etter fødselen var svært smertefulle. I desperasjon ringte Kristine sykehuset, men fikk beskjed om at «returretten» var utløpt etter 14 dager. Hun ringte på dag 16." },
    { type: "quote", text: "– Jeg følte meg som en kasteball og ble hele tiden henvist videre, men ingen kunne si noe konkret. Til slutt måtte jeg gråte på telefonen for å få hjelp, sier hun." },
    { type: "heading", text: "Ble deprimert av smertene" },
    { type: "paragraph", text: "Etter hvert mistet Kristine troen på at noen kunne hjelpe henne. Hun hadde senere vært hos fire leger som sa at alt var normalt." },
    { type: "quote", text: "– Det ødela så mye. Ikke bare kroppen, men hele identiteten min. Jeg følte jeg ble fratatt muligheten til å være til stede for barnet mitt. Jeg klarte ikke å «nyte barseltiden», slik alle sa at jeg skulle, sier hun." },
    { type: "paragraph", text: "Først etter 15 måneder kom hun til gynekolog Madeleine Engen hos CMedical, og allerede ved første konsultasjon forstod Madeleine hva problemet var." },
    { type: "quote", text: "– Jeg begynte å gråte da jeg kom til henne. Jeg var så redd for at hun også skulle si at alt var normalt. Men hun så problemet med én gang. Det var en lettelse jeg ikke kan beskrive, sier Bjerke." },
    { type: "paragraph", text: "To uker senere ble Kristine operert for vaginalt fremfall." },
    { type: "quote", text: "– Dessverre er ikke Kristines historie unik. Bekkenbunnstrening er viktig, men det holder ikke å få beskjed om «å bare knipe». Hvis skadene er for dype, er operasjon løsningen, sier Madeleine Engen, gynekolog og gründer av CMedical." },
    { type: "paragraph", text: "I dag har Bjerke fått livet sitt tilbake, men hun reagerer på hvor lite fokus det er på kvinnehelse etter fødsel – både fysisk og psykisk." },
    { type: "quote", text: "– Vi forberedes på graviditet og fødsel, men ingen snakker om hvor vanskelig tiden etterpå kan være. Det føles som om systemet bare slipper taket i oss etter at babyen er ute, sier hun." },
    { type: "source", text: "Se historien til Kristine, omtalt i Nettavisen", url: "https://www.nettavisen.no/nyheter/kristine-matte-til-fire-leger-for-a-fa-hjelp-knapt-hort-om-tilstanden-for/s/5-95-2603564" },
  ],

  "maria-falt-i-sahara-og-mellom-alle-stoler-i-helse-norge": [
    { type: "bold-intro", text: "Et uhell i Sahara i februar 2024 ble starten på et år fylt av smerte, mistillit og en kamp mot systemet. Nå vil Maria Teresa Cristofoli (54) løfte en stemme for de som ikke blir sett i det offentlige helsevesenet. – De som er sykemeldt over en lang periode, velger det ikke alltid selv, sier hun." },
    { type: "paragraph", text: "Det begynte med en aktiv ferie i Sahara. Maria er typen som trives med fysisk utfordring og eventyr, og bestemte seg for å buldre i ørkenen. Et feiltrinn endte med et brudd i høyrehånden og en dramatisk evakuering til et lokalt sykehus." },
    { type: "quote", text: "– Jeg hadde aldri brukket noe før, og stolte fullt og helt på at jeg var i trygge hender. Men da gipsen kom av etter tre uker og hånden så ut som voks, kjente jeg det første stikket av panikk. Og det skulle bare bli starten, sier hun." },
    { type: "heading", text: "En hånd som aldri ble bra" },
    { type: "paragraph", text: "På kontroll fikk Maria beskjed om at hevelsen og smerten ville gå over. Først etter mange uker fikk hun endelig møte en lege." },
    { type: "quote", text: "– Jeg ble satt i bås. En aktiv kvinne med masse driv ble plutselig redusert til en vanskelig pasient, sier hun." },
    { type: "paragraph", text: "Hun måtte kjempe for å bli tatt på alvor. Etter hvert fikk hun beskjed om at det skulle holdes et kirurgmøte hvor en ny operasjon kunne vurderes – men først om seks uker." },
    { type: "heading", text: "Vendepunktet" },
    { type: "paragraph", text: "Et vendepunkt kom da Maria i ventetiden valgte å bruke arbeidsgivers helseforsikring. Hun oppsøkte kirurg Jan-Ragnar Haugstvedt ved CMedical." },
    { type: "quote", text: "– Endelig følte jeg at noen så Maria: som har lyst til å jobbe 100 prosent igjen, som har lyst til å gå på ski og gjøre alle de tingene hun pleide å gjøre. Som ikke bare var en brikke i et stort offentlig apparat, sier hun." },
    { type: "quote", text: "– Han sa til og med etter operasjonen at skaden var enda større enn han først antok. Det var tett oppfølging, kommunikasjonen var tydelig og kirurgen var støttende. Nå forsto jeg virkelig verdien av å faktisk ha tid til pasienten, trygghet og ikke minst resultat, sier Maria." },
    { type: "quote", text: "– Et brudd vil normalt gro i løpet av seks uker. Når det ikke skjer, er det avgjørende å oppdage det i tide. Her måtte vi transplantere bein for å få bruddet til å gro. Å utsette en slik operasjon kan få alvorlige konsekvenser, sier Jan-Ragnar Haugstvedt." },
    { type: "heading", text: "En ripe i lakken for det offentlige" },
    { type: "quote", text: "– Jeg har følt meg som en belastning. Som en kost/nytte-sak. Og det skremmer meg, for hva med de som er enda sykere, mer sårbare, som ikke har ressursene til å stå på sitt?" },
    { type: "quote", text: "– Denne saken er en ripe i lakken for det offentlige Norge. Når det pågår en sykefraværsdebatt samtidig, så er det et paradoks. Det er ikke alle sykemeldte som har valgt det selv. Noen av oss har bare hatt ekstremt uflaks, sier hun." },
    { type: "paragraph", text: "Maria har nå en ny hverdag og kan endelig leve et aktivt liv igjen. Men historien hennes blir stående som en påminnelse om at det å bli sett og tatt på alvor kan være forskjellen på å bli frisk – eller bli stående fast." },
  ],

  "cmedical-og-nors-care-inngar-samarbeid-vil-styrke-kvinners-kunnskap-om-egen-helse": [
    { type: "bold-intro", text: "CMedical, som har Nordens mest komplette private kvinnehelsetilbud, og Nors Care, som står bak Norges største kvinnehelseapp Nørs, har inngått en strategisk samarbeidsavtale med mål om å øke kunnskapen om fertilitet blant kvinner." },
    { type: "paragraph", text: "Kvinnehelseappen Nørs står sterkt blant gravide og de som nylig har født i Norge og har over 200 000 kvinnelige brukere. Nå skal innholdet i Nørs breddes ut og hjelpe kvinner gjennom hele livet, fra første menstruasjon oppstår til og med overgangsalder." },
    { type: "quote", text: "– Vi har et sterkt fagmiljø innen fertilitet, både i Norge og i Sverige. Vi opplever at behovet for kunnskapsbasert og tilgjengelig informasjon om fertilitet er stort, og vi ønsker å bidra til å styrke helsekompetansen hos kvinner i fertil alder, sier Unni-Lovise Godager Berge, fungerende Markedsdirektør i CMedical." },
    { type: "quote", text: "– Sammen skal CMedical og Nors Care bidra til å tette kunnskapsgapet innen kvinnehelse og fertilitet. CMedicals sterke fagmiljø vil være en viktig ressurs for oss, sier Alexander Rein, en av grunnleggerne av Nors Care." },
    { type: "heading", text: "Oppsøk hjelp før det går for lang tid" },
    { type: "paragraph", text: "CMedical erfarer at mange som sliter med å bli gravide går for lenge uten å oppsøke hjelp eller forstå hva som kan være utfordringene." },
    { type: "quote", text: "– I denne plattformen har vi mulighet til å nå kvinner og par i en tidlig fase der de har et barneønske. Vi kan bidra til å belyse eventuelle utfordringer man kan oppleve rundt det å bli gravid, sier Birgitte Mitlid-Mork, gynekolog og fertilitetsspesialist ved CMedical." },
    { type: "quote", text: "– Der vi ser det kan være nødvendig, har vi i tillegg til fertilitetsbehandling gode muligheter for fertilitetsbevarende tiltak, med blant annet robotassistert kirurgi som den eneste private aktøren i Norge, avslutter hun." },
  ],

  "cmedical-kjoper-livio-oslo": [
    { type: "bold-intro", text: "CMedical satser ytterligere på kvinnehelse og fertilitetsbehandling, og kjøper opp Livio Oslo, landets første private fertilitetsklinikk og første klinikk med egen egg- og sædbank, på Majorstua i Oslo." },
    { type: "paragraph", text: "CMedical er Nordens ledende private aktør innen kvinnehelse. Med Livio Oslos lange erfaring og tunge posisjon i Norge vil CMedical nå bli en enda større aktør i det norske markedet for fertilitetsbehandlinger. I tillegg vil vi nå kunne tilby både sæd- og eggdonasjon fra norske donorer." },
    { type: "quote", text: "– Kvinnehelse og fertilitetsbehandling har vært et uttalt satsingsområde for CMedical siden 2022 og vi ser et stort potensial for vekst. Fra juni 2025 får vi større kapasitet og muligheten til å hjelpe langt flere med å oppnå drømmen om å få barn, sier Anne Flo, CEO i CMedical Norge." },
    { type: "quote", text: "– Vi er begeistret over at det er CMedical som kjøper opp den Norske delen av Livio, slik at tilbudet blir godt ivaretatt videre. Pasientene vi har i dag vil ikke merke noe til endringene, sier Anna-Carin Standberg, CEO Livio Group." },
    { type: "paragraph", text: "Inntil videre vil CMedical og Livio Oslo fortsette som separate selskaper. Oppkjøpet vil ikke få praktisk betydning for pasientenes pågående behandlingsløp." },
    { type: "heading", text: "Unikt tilbud til fertilitetspasienter i Norge" },
    { type: "paragraph", text: "CMedical er den første klinikken i Norden med fertilitetsbehandling og kirurgi – inkludert robotkirurgi – samlet på ett sted. Livio Oslo utfyller dagens tilbud med å kunne tilby sæd- og eggdonasjon fra norske donorer." },
    { type: "quote", text: "– Stadig flere par har vansker med å unnfange barn uten hjelp og våre fertilitetstjenester er høyt etterspurt. Med Livio Oslos toppteam og lange erfaring blir vi enda bedre rustet for å løse de mange utfordringene ufrivillige barnløse møter, sier Madeleine Engen, medgründer og fagansvarlig gynekolog i CMedical." },
  ],

  "tanken-slo-meg-ikke-at-det-kunne-vaere-meg": [
    { type: "bold-intro", text: "Når barn uteblir, tror mange automatisk at problemet ligger hos kvinnen, men i én av tre tilfeller skyldes det faktisk mannen. Likevel nøler mange menn med å sjekke seg. Nå deler Synne Pernille Jakobsen og Chris Kristiansen sin historie for å bryte tabuet – og oppfordrer par til å sjekke seg tidlig." },
    { type: "paragraph", text: "Etter måneder uten graviditet var paret overbevist om at utfordringen lå hos Synne. Hun kjente på en sterk følelse av ansvar, frustrasjon og sorg." },
    { type: "quote", text: "– Jeg tenkte rett og slett ikke på at det kunne være meg, sier Chris." },
    { type: "quote", text: "– Infertilitet kan ramme begge, og ingen er mer skyldig enn den andre. Likevel er det ofte kvinnen som forventes å «lykkes» med graviditeten, og som kjenner på ansvaret når det ikke går, sier Synne." },
    { type: "heading", text: "Rammer én av 20 menn" },
    { type: "paragraph", text: "Rundt 15 prosent av alle par opplever utfordringer med å bli gravide, og i 30-40 prosent av tilfellene ligger årsaken hos mannen. Samtidig har sædkvaliteten sunket betydelig de siste tiårene." },
    { type: "quote", text: "– Frykten for å bli sett ned på eller føle seg mindre maskulin gjør at mange velger å tie. Det er nok mye av grunnen til at det snakkes så lite om, sier Jackson Tok, fertilitetslege hos CMedical." },
    { type: "quote", text: "– Jeg innså at dette ikke var noe jeg burde skamme meg over, og at infertilitet ikke definerer meg. Vi har ikke mislyktes – vi bare trengte litt hjelp, sier Chris." },
    { type: "heading", text: "Det som var et problem, ble ikke lenger et problem" },
    { type: "paragraph", text: "Heldigvis tok paret raskt grep og startet en assistert befruktningsprosess hos CMedical. Med intracytoplasmatisk sædcelleinjeksjon (ICSI) ble paret gravide på første forsøk. I tillegg har de tre nedfryste embryoer." },
    { type: "quote", text: "– Etter innsettet kjente jeg umiddelbart at det var liv. Det var en helt ubeskrivelig følelse å endelig bli gravid, sier Synne." },
    { type: "quote", text: "– Det som var et problem, ble ikke lenger et problem. Og jeg tror dessverre at det kan være mange menn der ute som sitter med den samme utfordringen, men ikke tør å snakke om det. Det er ingen skam i å få hjelp, og det må vi få satt på agendaen, avslutter Chris." },
    { type: "subheading", text: "Om intracytoplasmatisk sædcelleinjeksjon" },
    { type: "paragraph", text: "ICSI er en avansert metode innen assistert befruktning som brukes når sædkvaliteten er redusert. Ved ICSI blir én enkelt sædcelle direkte injisert inn i egget med en tynn mikropipette for å øke sjansene for befruktning." },
  ],

  "ved-a-lukke-kvinnehelsegapet-kan-hver-kvinne-fa-syv-flere-friske-dager-i-lopet-av-et-ar": [
    { type: "bold-intro", text: "Økt fokus på kvinnehelse er ikke bare et politisk ansvar. Det er også økonomisk lønnsomt." },
    { type: "author", text: "Dr. Madeleine Engen, gynekolog og medgründer CMedical Kvinnehelse" },
    { type: "paragraph", text: "Ved å lukke kvinnehelsegapet kan vi tilføre norsk økonomi 80 milliarder kroner innen 2040, rapporterer McKinsey og World Economic Forum. Et forbedret helsetilbud til kvinner vil gi færre helseutfordringer og bedre livskvalitet, økt deltakelse i arbeidslivet og hevet produktivitet." },
    { type: "heading", text: "Kvinner er 25% mer syke enn menn" },
    { type: "paragraph", text: "Vi kan ikke snakke om sykefravær uten å snakke om kvinnehelse. Sammenlignet med menn tilbringer kvinner 25% mer av livet i dårlig helse. Dette helsegapet skyldes mangel på forskning og innovasjon, lang diagnostiseringstid og dårlig tilgang til effektiv behandling for kvinnesykdommer." },
    { type: "paragraph", text: "Kvinner i arbeidsfør alder bærer den største sykdomsbyrden. Etter kreft og hjerte- og karsykdommer er gynekologiske helseutfordringer den tredje største årsaken til kvinners tap av leveår i god helse." },
    { type: "heading", text: "Investeringer i kvinnehelse lønner seg" },
    { type: "paragraph", text: "McKinsey estimerer at for hver krone investert i forskning og behandling av kvinnehelseutfordringer forventes tre kroner i økonomisk vekst. Ved å lukke kvinnehelsegapet kan hver kvinne få syv flere friske dager i løpet av et år." },
    { type: "heading", text: "Hvordan kan vi lukke kvinnehelsegapet?" },
    { type: "paragraph", text: "Det er særlig tre tiltak som kan bidra til å lukke kvinnehelsegapet. For det første er vi nødt til å gjøre et kunnskaps- og kompetanseløft om kvinnesykdommer i både befolkningen og helsevesenet." },
    { type: "paragraph", text: "Videre er vi nødt til å få ned helsekøene og gi kvinner tilgang på riktig og effektiv behandling. Fire av fem etterlyser et tettere samarbeid mellom offentlig og privat helsetjeneste." },
    { type: "heading", text: "Samarbeid nødvendig" },
    { type: "paragraph", text: "Det finnes allerede private helsetjenester som er spesialiserte på overgangsalder, endometriose og andre gynekologiske helseutfordringer. Vi har den kompetansen som etterlyses og kan være med på et kunnskapsløft og å avlaste det offentlige helsevesenet." },
    { type: "bold-intro", text: "La oss samarbeide om å lukke kvinnehelsegapet i Norge. Det er vi alle tjent med." },
  ],
};
